import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { ShoppingCart, User, Package } from 'lucide-react';
import { useCart } from '../context/CartContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const { cart } = useCart();
  const navigate = useNavigate();

  const cartItemCount = cart?.items?.reduce((sum, item) => sum + item.quantity, 0) || 0;

  if (!user) {
    return null;
  }

  return (
    <nav className="navbar-shell sticky top-0 z-50">
      <div className="container mx-auto px-4 py-3">
        <div className="flex justify-between items-center">
          <Link to="/" className="text-2xl font-bold text-white">
            Croatia Gifts 🏰
          </Link>
          
          <div className="flex items-center gap-6">
            <Link to="/" className="nav-link">
              Shop
            </Link>
            
            {user?.isAdmin && (
              <Link to="/admin" className="nav-link flex items-center gap-1">
                <Package size={18} />
                Admin
              </Link>
            )}
            
            <Link to="/cart" className="relative nav-link">
              <ShoppingCart size={24} />
              {cartItemCount > 0 && (
                <span className="absolute -top-2 -right-2 bg-amber-400 text-slate-900 text-xs rounded-full w-5 h-5 flex items-center justify-center font-bold">
                  {cartItemCount}
                </span>
              )}
            </Link>
            
            <div className="flex items-center gap-3">
              <span className="text-sm text-slate-100/90">{user.email}</span>
              <button
                onClick={logout}
                className="bg-white/15 text-white px-4 py-1 rounded-lg hover:bg-white/25 transition border border-white/20"
              >
                Logout
              </button>
            </div>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
